uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    // sample previous uFrame
    ret = texture( sampler_fc_main, vUv ).xyz*(0.8 + q3*0.1);

    // darken (decay) over uTime
    ret *= 1.00; //or try: ret -= 0.004;

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


uv1 = (vUv-vec2(0.5,0.52))*uAspect.xy;
z = .1/(uv1.y);
uv2 = vec2 (uv1.x*1,1)*z + vec2(0,uTime/8);

mask = sat(texture(snh,uv2*0.1).r*8-6);
d  = (noise2(uv2-pix,+uTime)-noise2(uv2+pix,uTime)).r;
d*=d;
ret=mask*0.015*(z>0)*noise2(uv2,0);
//ret += sat(texture(snh, uv2*.02).r-.6)*(z<0)*.2;

uv2=fract(uv1*vec2(.8,.4)+vec2(.5,.5));
ret += d*GetBlur2(uv2)*(z>0)*2;

ret += sat(1-2/z)*.04*(1.5+sin(3*vRadius-uTime*0.1))*(2+slow_roam_cos) ;

ncity = sat(16*(uv1.y+.120)>pwnoise(vUv.x/8,0)) *sat(1-2/z);
ret-=ncity/16;
ncity = sat(6*(vUv.y-.2)>pwnoise(vUv.x/12,0)) *sat(1-2/z) * (abs(uv1.x)>0.07);
ncity2= sat(6*(vUv.y-.2)>pwnoise(vUv.x/12-0.003*uv1.x,0)) * (abs(uv1.x)>0.07);
ret-=ncity/2;

struc=sat(ncity-ncity2)*(pwnoise(1.5*vUv,0)-.5);
ret+=.15*struc;
ret+=struc*sat(1-vRadius)*GetBlur1(.5)*0.5;

ret=sat(ret);
radi = 1;
vec3 shine2 = 0;
for (int n=1; n <= anz;  n++)
{
  shine2 +=   1*Get1((vUv-.5)*radi+.5,radi)/anz;
  radi -= .5/anz;
}
ret += (2*shine2+ mix(GetPixel(vUv),2*GetBlur1(vUv),1*vRadius*vRadius))*.8;

ret += GetPixel((.5-vUv)*2+.5)*1 * sat(1-vRadius*3)*q27;

  fragColor = ret;
}
